import React from 'react'
import { Link } from 'react-router-dom'
import ComumRoutes from '../../ComumVars/ComumRoutes'

import "./peresseguranca.css"

const PeresSeguranca = () => {
  return (
    <section id="peresseguranca">

       <h1>Peres Segurança</h1>

       <Link className="link" to={ComumRoutes.ComumRoutes}>Grupo Peres</Link>
    </section>
  )
}

export default PeresSeguranca
